import"./modulepreload-polyfill-B5Qt9EMX.js";document.addEventListener("DOMContentLoaded",()=>{const o=document.getElementById("registerForm"),e=document.getElementById("errorMsg"),t=document.getElementById("successMsg");o.addEventListener("submit",async a=>{a.preventDefault();const d=document.getElementById("username").value,r=document.getElementById("email").value,c=document.getElementById("password").value;try{const s=await fetch("/api/auth/register",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({username:d,email:r,password:c})}),n=await s.json();if(!s.ok){e.textContent=n.message,e.style.display="block",t.style.display="none";return}t.textContent=n.message,t.style.display="block",e.style.display="none",setTimeout(()=>{document.body.classList.remove("page-ready"),setTimeout(()=>{window.location.href="/login"},180)},1500)}catch{e.textContent="Tidak bisa terhubung ke server",e.style.display="block"}})});
